import java.util.ArrayList;

class Main {
  public static void main(String[] args) {
    ArrayList<String> tasks = new ArrayList<String>();

    tasks.add("Clean");   // Index 0
    tasks.add("Code");    // Index 1
    tasks.add("Sleep");   // Index 2

    tasks.set(0, "Eat");  // Replaces 'Clean' with 'Eat'
    tasks.remove(2);      // Deletes 'Sleep'

    System.out.println(tasks);
  }
}
